public class Main {

    static long factorialRecursive(int n) {
        if (n <= 1) return 1;
        return n * factorialRecursive(n - 1);
    }

    static long factorialIterative(int n) {
        long result = 1;
        for (int i = 2; i <= n; i++) {
            result *= i;
        }
        return result;
    }

    public static void main(String[] args) {
        System.out.println("Faktoriyel tablosu (0-10):");
        for (int i = 0; i <= 10; i++) {
            System.out.println(i + "! = " + factorialIterative(i));
        }

        System.out.println("\nRecursive 5! = " + factorialRecursive(5));
        System.out.println("Iteratif 5! = " + factorialIterative(5));

        // Kombinasyon hesaplama: C(n,r) = n! / (r! * (n-r)!)
        int n = 5, r = 2;
        long combination = factorialIterative(n) / (factorialIterative(r) * factorialIterative(n - r));
        System.out.println("\nC(" + n + "," + r + ") = " + combination);
    }
}
